INSERT INTO "public"."activity_log" ("id", "company_id", "actor_type", "actor_id", "action", "entity_type", "entity_id", "agent_id", "details", "created_at", "run_id") VALUES ($paperclip$5f67c491-fa67-490f-83b4-24d5efdb41f0$paperclip$, $paperclip$4a314bff-55a4-4939-bbb7-b3d73c7db1ce$paperclip$, $paperclip$user$paperclip$, $paperclip$local-board$paperclip$, $paperclip$company.updated$paperclip$, $paperclip$company$paperclip$, $paperclip$4a314bff-55a4-4939-bbb7-b3d73c7db1ce$paperclip$, NULL, $paperclip${"name":"Foreman","brandColor":null,"description":"Here's a description you can drop into Paperclip:  ---  **Foreman** is a multi-tenant SaaS platform that provides autonomous AI agent operations for solopreneurs and small businesses. The core value proposition is \"AI agents for the rest of us\" — giving non-technical operators access to a managed multi-agent runtime without infrastructure complexity or unpredictable API costs.  **Business model:** Flat-rate pricing powered by multi-tenant GPU utilization. Foreman runs self-hosted inference on owned GPU hardware (via RunPod Secure Cloud), spreading fixed infrastructure costs across all tenants. This makes the economics work at scale without passing per-token costs to customers.  **Product structure:** Work is organized into a four-level hierarchy — **Bases** (a persistent environment with an overall objective and a named team of agents) contain **Projects** (bounded units of work with defined deliverables) which contain **Tasks** which produce **Deliverables**. Each customer operates in an isolated workspace identified by a `workspace_slug`.  **Inference stack:** Three always-on specialized roles — an **Executor** (Qwen3-14B-AWQ, fast general-purpose task completion), a **Planner** (Qwen3-30B-A3B MoE AWQ, complex reasoning and decomposition), and an **Embedder** (Qwen3-Embedding-8B, semantic search and memory). Models are served via vLLM. There is no fallback routing between models — if a model is unavailable, the system returns a 503.  **Agent runtime:** OpenClaw (MIT-licensed, local-first agent runtime) handles agent execution. Paperclip provides orchestration on top of OpenClaw. Agents must never hallucinate data — if real data is required, it must arrive through actual tool access or explicit context; estimation is prohibited. Agents should not escalate decisions they have sufficient data or role authority to make themselves.  **Internal workspace:** The `foreman` workspace (`workspace_slug = 'foreman'`) is Foreman's own internal operating environment, where agents manage the platform codebase and operations. This workspace is distinct from all customer workspaces.  **Moat:** Operational, not technical. The differentiation is multi-tenancy GPU utilization economics, simplified onboarding over raw open-source tooling, and a managed runtime that abstracts away infrastructure decisions from end users.  ---  Trim or expand any section depending on how much context Paperclip surfaces to agents at runtime."}$paperclip$, $paperclip$2026-04-09T01:48:45.696Z$paperclip$, NULL);
-- paperclip statement breakpoint 69f6f3f1-42fd-46a6-bf17-d1d85f8f3900
INSERT INTO "public"."activity_log" ("id", "company_id", "actor_type", "actor_id", "action", "entity_type", "entity_id", "agent_id", "details", "created_at", "run_id") VALUES ($paperclip$375e90fe-6d64-4520-82d1-9d35ecc6502c$paperclip$, $paperclip$4a314bff-55a4-4939-bbb7-b3d73c7db1ce$paperclip$, $paperclip$user$paperclip$, $paperclip$local-board$paperclip$, $paperclip$company.updated$paperclip$, $paperclip$company$paperclip$, $paperclip$4a314bff-55a4-4939-bbb7-b3d73c7db1ce$paperclip$, NULL, $paperclip${"name":"Foreman","brandColor":null,"description":"**Foreman** is a multi-tenant SaaS platform that provides autonomous AI agent operations for solopreneurs and small businesses. The core value proposition is \"AI agents for the rest of us\" — giving non-technical operators access to a managed multi-agent runtime without infrastructure complexity or unpredictable API costs.  **Business model:** Flat-rate pricing powered by multi-tenant GPU utilization. Foreman runs self-hosted inference on owned GPU hardware (via RunPod Secure Cloud), spreading fixed infrastructure costs across all tenants. This makes the economics work at scale without passing per-token costs to customers.  **Product structure:** Work is organized into a four-level hierarchy — **Bases** (a persistent environment with an overall objective and a named team of agents) contain **Projects** (bounded units of work with defined deliverables) which contain **Tasks** which produce **Deliverables**. Each customer operates in an isolated workspace identified by a `workspace_slug`.  **Inference stack:** Three always-on specialized roles — an **Executor** (Qwen3-14B-AWQ, fast general-purpose task completion), a **Planner** (Qwen3-30B-A3B MoE AWQ, complex reasoning and decomposition), and an **Embedder** (Qwen3-Embedding-8B, semantic search and memory). Models are served via vLLM. There is no fallback routing between models — if a model is unavailable, the system returns a 503.  **Agent runtime:** OpenClaw (MIT-licensed, local-first agent runtime) handles agent execution. Paperclip provides orchestration on top of OpenClaw. Agents must never hallucinate data — if real data is required, it must arrive through actual tool access or explicit context; estimation is prohibited. Agents should not escalate decisions they have sufficient data or role authority to make themselves.  **Internal workspace:** The `foreman` workspace (`workspace_slug = 'foreman'`) is Foreman's own internal operating environment, where agents manage the platform codebase and operations. This workspace is distinct from all customer workspaces.  **Moat:** Operational, not technical. The differentiation is multi-tenancy GPU utilization economics, simplified onboarding over raw open-source tooling, and a managed runtime that abstracts away infrastructure decisions from end users."}$paperclip$, $paperclip$2026-04-09T01:49:09.801Z$paperclip$, NULL);
-- paperclip statement breakpoint 69f6f3f1-42fd-46a6-bf17-d1d85f8f3900
