INSERT INTO "public"."companies" ("id", "name", "description", "status", "budget_monthly_cents", "spent_monthly_cents", "created_at", "updated_at", "issue_prefix", "issue_counter", "require_board_approval_for_new_agents", "brand_color", "pause_reason", "paused_at", "feedback_data_sharing_enabled", "feedback_data_sharing_consent_at", "feedback_data_sharing_consent_by_user_id", "feedback_data_sharing_terms_version") VALUES ($paperclip$00ca3ed6-7ad2-43f1-a862-5d5295bbac0c$paperclip$, $paperclip$Foreman-Isolation-B$paperclip$, NULL, $paperclip$active$paperclip$, 0, 0, $paperclip$2026-04-09T00:06:05.028Z$paperclip$, $paperclip$2026-04-09T00:06:05.028Z$paperclip$, $paperclip$FORA$paperclip$, 9, true, NULL, NULL, NULL, false, NULL, NULL, NULL);
